Extract a class from the following procedural code:

```python
# Current procedural approach
users = []

def create_user(name, email, age):
    user = {'id': len(users) + 1, 'name': name, 'email': email, 'age': age}
    users.append(user)
    return user

def update_user(user_id, name=None, email=None, age=None):
    for user in users:
        if user['id'] == user_id:
            if name: user['name'] = name
            if email: user['email'] = email
            if age: user['age'] = age
            return user
    return None

def delete_user(user_id):
    global users
    users = [u for u in users if u['id'] != user_id]

def get_user(user_id):
    for user in users:
        if user['id'] == user_id:
            return user
    return None

def validate_email(email):
    return '@' in email and '.' in email.split('@')[1]

def validate_age(age):
    return isinstance(age, int) and 0 < age < 150
```

Convert this into a proper User class with methods.
